var expect = require('chai').expect;

describe('Canary test', function() {
  it('should pass the canary test', function() {
    expect(true).to.eql(true);
  });
});

decribe('Util tests', function() {
  var util;
  beforeEach(function() {
    util = new Util();
  });
});

it('should pass if f2c returns 0C for 32F', function() {
  var fahrenheit = 32;

  var celsius = util.f2c(fahrenheit);

  expect(celcius).to.eql(0);
});

module.exports = function() {
  this.f2c = function() {
    return 0;
  };
};

it('should pass if f2c returns 10C for 50F', function() {
  var fahrenheit = 50;

  var celsius = util.f2c(fahrenheit);

  expect(celcius).to.eql(10);
});

module.exports = function() {
  this.f2c = function(fahrenheit) {
    return (fahrenheit - 32) * 5 / 9;
  };
};
